import{_ as t,c as a,o,ag as r}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md","lastUpdated":1777110900000}'),i={name:"faq.md"};function n(s,e,l,d,c,h){return o(),a("div",null,e[0]||(e[0]=[r('<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h1><p>Find answers to common questions about OptionBay&#39;s features, compatibility, and setup.</p><h2 id="general-questions" tabindex="-1">General Questions <a class="header-anchor" href="#general-questions" aria-label="Permalink to &quot;General Questions&quot;">​</a></h2><h3 id="is-optionbay-compatible-with-my-theme" tabindex="-1">Is OptionBay compatible with my theme? <a class="header-anchor" href="#is-optionbay-compatible-with-my-theme" aria-label="Permalink to &quot;Is OptionBay compatible with my theme?&quot;">​</a></h3><p>Yes! OptionBay is designed to be theme-agnostic. It uses the standard WooCommerce <code>woocommerce_before_add_to_cart_button</code> hook to display options and provides global settings for font sizes, swatch dimensions, and orientation to help you match your theme&#39;s aesthetic. If you encounter layout issues, you can add custom CSS to your theme&#39;s stylesheet targeting the <code>optionbay-</code> prefixed class names.</p><h3 id="does-optionbay-work-with-variable-products" tabindex="-1">Does OptionBay work with Variable Products? <a class="header-anchor" href="#does-optionbay-work-with-variable-products" aria-label="Permalink to &quot;Does OptionBay work with Variable Products?&quot;">​</a></h3><p>Absolutely. OptionBay options will appear on both <strong>Simple</strong> and <strong>Variable</strong> product pages. You can even use assignment rules to show specific option groups only for certain product types by targeting product tags or categories.</p><h3 id="does-this-plugin-slow-down-my-site" tabindex="-1">Does this plugin slow down my site? <a class="header-anchor" href="#does-this-plugin-slow-down-my-site" aria-label="Permalink to &quot;Does this plugin slow down my site?&quot;">​</a></h3><p>Performance was a primary goal during development. OptionBay uses a modern React-based admin that loads only when needed (code splitting separates the builder from the settings page), and the frontend script is a lightweight vanilla JavaScript file that is highly optimized to ensure it doesn&#39;t impact your Google PageSpeed scores.</p><h3 id="how-many-option-groups-can-i-create" tabindex="-1">How many Option Groups can I create? <a class="header-anchor" href="#how-many-option-groups-can-i-create" aria-label="Permalink to &quot;How many Option Groups can I create?&quot;">​</a></h3><p>There is no limit. You can create as many Option Groups as your store requires. Each group is stored as a WordPress custom post type, so performance scales naturally with your WordPress hosting.</p><h3 id="can-i-duplicate-an-option-group" tabindex="-1">Can I duplicate an Option Group? <a class="header-anchor" href="#can-i-duplicate-an-option-group" aria-label="Permalink to &quot;Can I duplicate an Option Group?&quot;">​</a></h3><p>Yes. On the <strong>Products &gt; Options</strong> page, hover over any group and click the <strong>Duplicate</strong> action. This creates an exact copy of the group — including all fields, pricing, conditional logic, and assignment rules — which you can then modify as needed.</p><h2 id="pricing-cart" tabindex="-1">Pricing &amp; Cart <a class="header-anchor" href="#pricing-cart" aria-label="Permalink to &quot;Pricing &amp; Cart&quot;">​</a></h2><h3 id="how-are-addon-prices-displayed-in-the-cart" tabindex="-1">How are addon prices displayed in the cart? <a class="header-anchor" href="#how-are-addon-prices-displayed-in-the-cart" aria-label="Permalink to &quot;How are addon prices displayed in the cart?&quot;">​</a></h3><p>Addon prices are added to the product&#39;s base price. On the cart and checkout pages, WooCommerce will show the updated total price. OptionBay also displays a clear list of the selected options and their individual costs below the product name in the cart items.</p><h3 id="what-price-types-are-available" tabindex="-1">What price types are available? <a class="header-anchor" href="#what-price-types-are-available" aria-label="Permalink to &quot;What price types are available?&quot;">​</a></h3><p>OptionBay supports the following price types:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Price Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>No Price</strong></td><td style="text-align:left;">The field/option does not affect the product price.</td></tr><tr><td style="text-align:left;"><strong>Flat Fee</strong></td><td style="text-align:left;">A fixed amount is added (e.g., +$5.00).</td></tr><tr><td style="text-align:left;"><strong>Percentage of Base</strong></td><td style="text-align:left;">Calculates the addon cost based on the product&#39;s base price (e.g., 10% of a $100 product adds $10.00).</td></tr><tr><td style="text-align:left;"><strong>Per Character</strong></td><td style="text-align:left;">Cost multiplied by the number of characters typed. Available only for Text and Textarea fields.</td></tr><tr><td style="text-align:left;"><strong>Formula</strong></td><td style="text-align:left;">Advanced math-based pricing using placeholders like <code>[value]</code>, <code>[char_count]</code>, <code>[base_price]</code>, and <code>[quantity]</code>.</td></tr></tbody></table><h3 id="are-addon-prices-included-in-the-order-total" tabindex="-1">Are addon prices included in the order total? <a class="header-anchor" href="#are-addon-prices-included-in-the-order-total" aria-label="Permalink to &quot;Are addon prices included in the order total?&quot;">​</a></h3><p>Yes. All addon prices are fully integrated into the WooCommerce cart and checkout totals. They appear on the Thank You page, in customer and admin order emails, and in all PDF invoice plugins that read standard WooCommerce order item meta.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="why-aren-t-my-options-appearing-on-the-product-page" tabindex="-1">Why aren&#39;t my options appearing on the product page? <a class="header-anchor" href="#why-aren-t-my-options-appearing-on-the-product-page" aria-label="Permalink to &quot;Why aren&#39;t my options appearing on the product page?&quot;">​</a></h3><p>Please check the following:</p><ol><li><strong>Option Group Status:</strong> Is the group set to &quot;Published&quot;? Draft groups are never displayed.</li><li><strong>Assignment Rules:</strong> Have you correctly assigned the group to that product, category, or tag? Check for any active exclusion rules that might be overriding an inclusion.</li><li><strong>WooCommerce Version:</strong> Ensure you are running a supported version of WooCommerce (6.1+).</li><li><strong>Theme Hooks:</strong> Your theme must use the standard <code>woocommerce_before_add_to_cart_button</code> hook. Most themes do, but some custom builders might require manual placement.</li><li><strong>Cache:</strong> Clear any caching plugin caches after making changes to assignment rules.</li></ol><h3 id="my-add-to-cart-button-is-disabled-why" tabindex="-1">My &quot;Add to Cart&quot; button is disabled. Why? <a class="header-anchor" href="#my-add-to-cart-button-is-disabled-why" aria-label="Permalink to &quot;My &quot;Add to Cart&quot; button is disabled. Why?&quot;">​</a></h3><p>This usually means a <strong>Required Field</strong> has not been filled out. Look for the red asterisk (*) next to field labels. Once all required options are selected or filled in, the button will automatically re-enable.</p><h3 id="my-conditional-logic-isn-t-working-what-should-i-check" tabindex="-1">My conditional logic isn&#39;t working. What should I check? <a class="header-anchor" href="#my-conditional-logic-isn-t-working-what-should-i-check" aria-label="Permalink to &quot;My conditional logic isn&#39;t working. What should I check?&quot;">​</a></h3><ol><li><strong>Same Group:</strong> Conditional logic only works between fields <strong>in the same Option Group</strong>. Cross-group rules are not supported.</li><li><strong>Value Match:</strong> The value in the rule must exactly match what the field submits. For select/radio/checkbox fields, this is the option&#39;s <strong>Value</strong> (the auto-generated lowercase string), not the Label.</li><li><strong>Debug Mode:</strong> Enable <a href="./settings.html">Debug Mode</a> in the settings to see detailed logs that can help identify logic evaluation issues.</li></ol><h2 id="support" tabindex="-1">Support <a class="header-anchor" href="#support" aria-label="Permalink to &quot;Support&quot;">​</a></h2><p>Need more help? Visit our website at <a href="https://wpanchorbay.com" target="_blank" rel="noreferrer">wpanchorbay.com</a> or reach out to our support team through the WordPress.org forums.</p>',31)]))}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
